INSERT INTO bracelets (name, image, description, details, price) VALUES
('Vine Hinged Bangle', 'https://ibb.co/z7wkH1T', 'Inspired by the natural world, Tiffany Victoria designs capture the fluid movement of flowers, vines and leaves with a mix of expertly cut diamonds. This hinged bangle is crafted of 18k gold that features a contrast of high polish and sandblasted finishes. Round brilliant diamonds set in an alternating pattern play off the light and accentuate the vine motif. When too many diamonds are never enough, Tiffany Victoria is the ultimate way to shine. Wear this bangle on its own or paired with your favorite diamond tennis bracelet for sparkle you can’t ignore.', ARRAY['18k yellow gold with round brilliant diamonds', 'Size medium', 'Fits wrists up to 6.25"', 'Carat total weight .46', 'Product number:69524346'], '$10,200'),
('X Closed Narrow Hinged Bangle', 'https://ibb.co/q5xm8R5', 'Traced with over 100 round brilliant diamonds, this closed hinged bangle is designed with an iconic knife edge profile, a Tiffany code of the house since the introduction of the Tiffany® Setting engagement ring in 1886. Wearable emblems inspired by the Roman numerals on the iconic clock at the New York flagship store, the Atlas X collection is a reminder to take time into your own hands and treasure what matters most. Pair this narrow bangle with other Tiffany bracelets, with or without diamonds, for a strong style statement.', ARRAY['18k rose gold with over 100 round brilliant diamonds', 'Size medium', 'Fits wrists up to 6.25"', 'Carat total weight .33', 'Product number:68174147'], '$12,000.00'),
('36 Stone Bracelet', 'https://ibb.co/D8tqcS3', 'Jean Schlumberger’s visionary creations are among the world’s most intricate designs. Blazing with diamonds, this striking bracelet makes a dazzling statement.', ARRAY['18k gold and platinum with round brilliant diamonds', 'Carat total weight 2.95', 'Product number:60108488'], '$39,000');
